import{j as t}from"./react-vendor-y-feJQYq.js";import{L as s}from"./LegalPage-B0iAoeqX.js";import{u as a}from"./index-ViRZz4FO.js";import"./vendor-CafVgpJs.js";import"./Layout-BofuPsx4.js";import"./i18n-vendor-2fjYU3KL.js";import"./motion-vendor-DS6QkThC.js";const e={it:{seo:{title:"Cookie Policy — Finch-AI",description:"Informativa sull'uso dei cookie e delle tecnologie simili sul sito Finch-AI.",keywords:"cookie policy, cookie, GDPR, Finch-AI"},lastUpdated:"Ultimo aggiornamento: 31 maggio 2026",title:"Cookie Policy",intro:"Questa Cookie Policy spiega cosa sono i cookie, quali tipologie utilizziamo su questo sito e come puoi gestirne le preferenze.",sections:[{heading:"1. Cosa sono i cookie",blocks:["I cookie sono piccoli file di testo che i siti web salvano sul dispositivo dell'utente durante la navigazione. Consentono al sito di funzionare correttamente, di ricordare le preferenze e di raccogliere informazioni statistiche."]},{heading:"2. Tipologie di cookie utilizzati",blocks:[["Cookie tecnici/necessari: indispensabili per il corretto funzionamento del sito (es. preferenze di lingua e tema). Non richiedono consenso.","Cookie analitici: utilizzati per raccogliere informazioni statistiche e anonime sull'uso del sito, al fine di migliorarne i contenuti. Vengono installati solo previo consenso.","Cookie di terze parti: eventualmente impostati da servizi esterni (es. video incorporati, social network) quando interagisci con tali contenuti."]]},{heading:"3. Gestione dei cookie",blocks:["Puoi gestire o disabilitare i cookie in qualsiasi momento dalle impostazioni del tuo browser. La disattivazione dei cookie tecnici potrebbe compromettere alcune funzionalità del sito.","Le principali guide per la gestione dei cookie sono disponibili nelle pagine di supporto dei browser (Chrome, Firefox, Safari, Edge)."]},{heading:"4. Titolare e contatti",blocks:["Il Titolare del trattamento è Finch-AI, Via Enrico Mattei 18, 67043 Celano (AQ), P.IVA 02213890664. Per informazioni sull'uso dei cookie scrivi a info@finch-ai.it.","Per il trattamento dei dati personali consulta la Privacy Policy."]}]},en:{seo:{title:"Cookie Policy — Finch-AI",description:"How the Finch-AI website uses cookies and similar technologies.",keywords:"cookie policy, cookies, GDPR, Finch-AI"},lastUpdated:"Last updated: 31 May 2026",title:"Cookie Policy",intro:"This Cookie Policy explains what cookies are, which types we use on this website and how you can manage your preferences.",sections:[{heading:"1. What cookies are",blocks:["Cookies are small text files that websites save on the user's device while browsing. They allow the site to work properly, remember preferences and collect statistical information."]},{heading:"2. Types of cookies we use",blocks:[["Strictly necessary cookies: essential for the proper functioning of the site (e.g. language and theme preferences). They do not require consent.","Analytics cookies: used to collect anonymous statistical information about how the site is used, in order to improve its content. They are only set with consent.","Third-party cookies: possibly set by external services (e.g. embedded videos, social networks) when you interact with such content."]]},{heading:"3. Managing cookies",blocks:["You can manage or disable cookies at any time through your browser settings. Disabling necessary cookies may affect some features of the website.","The main guides for managing cookies are available on the support pages of each browser (Chrome, Firefox, Safari, Edge)."]},{heading:"4. Controller and contacts",blocks:["The data controller is Finch-AI, Via Enrico Mattei 18, 67043 Celano (AQ), Italy, VAT no. 02213890664. For information about the use of cookies, write to info@finch-ai.it.","For the processing of personal data, see the Privacy Policy."]}]}};function h(){const i=a(),o=e[i]||e.it;return t.jsx(s,{canonical:"https://finch-ai.it/cookie-policy",...o})}export{h as default};
